import { Component, EventEmitter, Input, Output } from '@angular/core';
import { ResumeTemplate } from '../../../core/models/resume.model';

@Component({
  selector: 'app-template-card',
  templateUrl: './template-card.component.html'
})
export class TemplateCardComponent {
  @Input() template!: ResumeTemplate;
  @Input() atsScore = 92;
  @Input() usedCountLabel = '10,000+ students';
  @Output() preview = new EventEmitter<ResumeTemplate>();

  get tags(): string[] {
    try {
      const parsed = JSON.parse(this.template.tagsJson);
      return Array.isArray(parsed) ? parsed : [];
    } catch {
      return [];
    }
  }
}
<article class="shell-card overflow-hidden p-4">
  <div class="overflow-hidden rounded-[24px] bg-[#f8f9ff]">
    <img [src]="template.previewImageUrl" [alt]="template.name" class="h-[320px] w-full object-cover object-top">
  </div>
  <div class="p-4">
    <div class="flex items-start justify-between gap-3">
      <div>
        <h3 class="text-xl font-extrabold text-[#17172b]">{{ template.name }}</h3>
        <p class="mt-2 text-sm text-[#667085]">{{ template.category }} · {{ template.layoutType }} · ATS Friendly</p>
      </div>
      <span class="rounded-full bg-[#ecfdf3] px-3 py-1.5 text-xs font-bold text-[#16a34a]">ATS Friendly</span>
    </div>

    <div class="mt-4 flex flex-wrap gap-2">
      <span *ngFor="let tag of tags" class="rounded-full bg-[#edf2ff] px-3 py-1.5 text-xs font-semibold text-[#5b5cf0]">{{ tag }}</span>
    </div>

    <div class="mt-4 grid gap-2 text-sm text-[#667085]">
      <div>ATS Score: <span class="font-semibold text-[#17172b]">{{ atsScore }}/100</span></div>
      <div>Best for {{ template.roleType | titlecase }}s</div>
      <div>Used by {{ usedCountLabel }}</div>
    </div>

    <div class="mt-5 flex gap-3">
      <a [routerLink]="['/resume-builder/create', template.id]" class="btn-primary flex-1 text-sm">Use Template</a>
      <a [routerLink]="['/templates', template.id, 'preview']" class="btn-secondary text-sm">Preview</a>
    </div>
  </div>
</article>
